// CHECK-LABEL: define dso_local i32 @test_vmulas_s8_xacc(
// CHECK-SAME: ptr noundef [[SRC1:%.*]], ptr noundef [[SRC2:%.*]]) local_unnamed_addr #[[ATTR3:[0-9]+]] {
